return items.map((item, idx) => {
  const j = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || $items('Webhook MTR Upload1')[idx]?.json || {};
  const out = j.output || j.data?.output || j.data || j.result?.output || j.result || j;
  return {
    json: {
      mtr_id: j.mtr_id || original.mtr_id || original.mtrId || '',
      output: out,
    }
  };
});

return items.map((item, idx) => {
  const j = item.json || {};
  const text = (j.content && j.content[0] && j.content[0].text) || '';
  let obj = {};
  try {
    obj = JSON.parse(text.trim());
  } catch (e) {
    const a = text.indexOf('{');
    const b = text.lastIndexOf('}');
    if (a >= 0 && b > a) {
      try { obj = JSON.parse(text.slice(a, b + 1)); } catch (_) {}
    }
  }
  return {
    json: {
      ...j,
      output: obj,
    },
    binary: item.binary
  };
});

const promises = items.map(async (item, idx) => {
  const j = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || {};
  let pdf = j.file_content_base64 || original.file_content_base64 || '';

  if (!pdf) {
    try {
      const buf = await this.helpers.getBinaryDataBuffer(idx, 'data0');
      pdf = buf.toString('base64');
    } catch (e) {}
  }

  const prompt = (j.selected_prompt || j.extraction_system_message || '').toString().trim();
  if (!pdf || !prompt) {
    throw new Error('Missing pdf or prompt');
  }

  return {
    json: {
      ...original,
      ...j,
      file_content_base64: original.file_content_base64 || j.file_content_base64,
      claude_extract_body: {
        model: 'claude-sonnet-4-6',
        max_tokens: 8192,
        messages: [
          {
            role: 'user',
            content: [
              { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: pdf } },
              { type: 'text', text: prompt }
            ]
          }
        ]
      }
    }
  };
});

return Promise.all(promises);

