return items.map(item => {
  const j = item.json || {};
  let prompt = (j.selected_prompt || j.extraction_system_message || '').toString().trim();
  let prompt_missing = false;
  if (!prompt) {
    prompt_missing = true;
    // Minimal safe fallback to avoid hard stop
    prompt = 'Return {}';
  }
  return { 
    json: { ...j, selected_prompt: prompt, extraction_system_message: prompt, prompt_missing }
  };
});

return items.map((item, idx) => {
  const auth = $items("Auth to Odoo1")[0]?.json || {};
  // Keep payload fields authoritative (db_name, odoo_url, etc.)
  return { json: { ...auth, ...item.json } };
});

return items.flatMap(item => {
  const j = item.json || {};
  const heat = (j.heat_number || '').toString().trim();
  const batch = (j.batch_number || '').toString().trim();
  const mtrId = (j.mtr_id || '').toString().trim();

  if (!batch && !heat) {
    // Skip records without the primary identifier
    j.validation_warning = 'Missing batch_number';
    return [];
  }

  if (batch) {
    j.batch_number = batch;
  }

  const badTokens = ['fewf', 'ferf', 'ref', 'fre'];
  const lowered = JSON.stringify({
    manufacturer: j.manufacturer,
    grade: j.grade,
    certificate_number: j.certificate_number,
  }).toLowerCase();
  if (badTokens.some(t => lowered.includes(t))) {
    // Mark garbage but don't block
    j.validation_warning = 'Garbage tokens detected';
  }

  return [{ json: j }];
});

return items.flatMap((item, idx) => {
  const src = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || $items('Webhook MTR Upload1')[idx]?.json || {};
  const normalizeId = (v) => {
    if (v === undefined || v === null) return '';
    if (typeof v === 'number') return String(v);
    const s = String(v).trim();
    if (!s) return '';
    const m = s.match(/\d+/);
    return m ? m[0] : s;
  };
  const baseMtrId = normalizeId(src.mtr_id || src.mtrId || original.mtr_id || original.mtrId || '');
  const fileName = (src.file_name || src.source_file || original.file_name || original.source_file || '').toString().trim();
    const parseMaybeJson = (v) => {
    if (!v) return null;
    if (typeof v === 'object') return v;
    if (typeof v !== 'string') return null;
    const s = v.trim();
    try {
      return JSON.parse(s);
    } catch (_) {
      const a = s.indexOf('{');
      const b = s.lastIndexOf('}');
      if (a >= 0 && b > a) {
        try { return JSON.parse(s.slice(a, b + 1)); } catch (__) {}
      }
      return null;
    }
  };

  const parsedOutput = parseMaybeJson(src.output);
  const parsedText = parseMaybeJson(src.text);
  const root =
    (src.output && (src.output.certificateHeader || src.output.materialTestRecords)) ? src.output :
    (src.certificateHeader || src.materialTestRecords) ? src :
    (parsedOutput && parsedOutput.output && (parsedOutput.output.certificateHeader || parsedOutput.output.materialTestRecords)) ? parsedOutput.output :
    (parsedOutput && (parsedOutput.certificateHeader || parsedOutput.materialTestRecords)) ? parsedOutput :
    (parsedText && parsedText.output && (parsedText.output.certificateHeader || parsedText.output.materialTestRecords)) ? parsedText.output :
    (parsedText && (parsedText.certificateHeader || parsedText.materialTestRecords)) ? parsedText :
    (src.data && src.data.output && (src.data.output.certificateHeader || src.data.output.materialTestRecords)) ? src.data.output :
    (src.data && (src.data.certificateHeader || src.data.materialTestRecords)) ? src.data :
    src;

  const records =
    (Array.isArray(root.materialTestRecords) && root.materialTestRecords) ||
    (Array.isArray(root.material_test_records) && root.material_test_records) ||
    [];

  const misc = root.miscellaneous || root.misc || {};
  const hdr = root.certificateHeader || root.header || {};

  const asStr = (v) => (v === undefined || v === null ? '' : String(v).trim());
  const normalizeNumberString = (raw) => {
    if (raw === undefined || raw === null) return '';
    let s = String(raw).trim();
    if (!s) return '';
    if (s.includes(',') && !s.includes('.')) {
      const m = s.match(/^\d{1,3},\d{1,6}$/);
      if (m) s = s.replace(',', '.');
      else s = s.replace(/,/g, '');
    } else {
      s = s.replace(/,/g, '');
    }
    return s;
  };

  const asNum = (v) => {
    if (v === undefined || v === null || v === '') return null;
    if (typeof v === 'number') return Number.isFinite(v) ? v : null;
    const cleaned = normalizeNumberString(v);
    if (!cleaned) return null;
    const m = cleaned.match(/-?\d+(?:\.\d+)?/);
    return m ? Number(m[0]) : null;
  };

  const asChemNum = asNum;
  const pick = (obj, keys) => {
    for (const k of keys) {
      if (obj && obj[k] !== undefined && obj[k] !== null && String(obj[k]).trim() !== '') return obj[k];
    }
    return '';
  };

  const splitHeats = (h) => {
    const s0 = String(h || '').trim();
    if (s0 === '') return [''];
    const s = s0.replace(/\band\b/gi, ',').replace(/[;\/\n&]+/g, ',');
    const parts = s.split(',').map(p => p.trim()).filter(Boolean);
    return parts.length ? parts : [s0];
  };

  const mapRec = (rec) => {
    const chem = rec.chemicalComposition || rec.chemical || rec.chemistry || {};
    const mech = rec.mechanicalProperties || rec.mechanical || {};
    const phys = rec.physicalProperties || rec.physical || {};
    const charpy = rec.charpyImpactTest || rec.charpy || {};
    const heat = asStr(pick(rec, ['heatNumber', 'heat_number', 'heatNo', 'heat_no', 'heat', 'heat#', 'heatId', 'heat_id']));
    const batch = asStr(pick(rec, ['batchNumber', 'batch_number', 'batchNo', 'batch_no', 'bundleNumber', 'bundleNo', 'bundle_no', 'bundle', 'tag', 'tagNumber', 'tag_no', 'tag#', 'lot', 'lotNumber', 'lot_no', 'coil', 'coilNumber', 'coil_no']));
    const testNo = asStr(pick(rec, ['testNumber', 'test_number', 'testNo', 'test_no']));
    const batchFinal = (!batch && testNo && /^DA\d+/i.test(testNo)) ? testNo : batch;
    return {
      heat_number: heat,
      batch_number: batchFinal,
      piece_no: asStr(pick(rec, ['piece_no', 'pieceNo', 'piece_number', 'pieceCount', 'piece_count']) || pick(mech, ['piece_no', 'pieceNo', 'piece_number'])),
      grade: asStr(pick(hdr, ['grade', 'materialGrade', 'material_grade', 'material', 'specification']) || pick(rec, ['grade', 'materialGrade', 'material_grade', 'material', 'specification']) || pick(misc, ['standard', 'specification', 'specifications'])),
      manufacturer: asStr(pick(hdr, ['manufacturer', 'mill', 'supplier', 'issuedFrom', 'issued_from']) || src.manufacturer_hint || src.manufacturer_name || src.detected_manufacturer || ''),
      certificate_number: asStr(pick(hdr, ['certificateNumber', 'certificate_number', 'certNumber', 'certNo', 'certificateNo', 'testReference', 'test_reference', 'reportNumber'])),
      certificate_date: asStr(pick(hdr, ['certificateDate', 'certificate_date', 'date', 'issueDate', 'issuedDate', 'reportDate'])),
      c: asChemNum(pick(chem, ['C', 'c'])),
      mn: asChemNum(pick(chem, ['Mn', 'mn'])),
      si: asChemNum(pick(chem, ['Si', 'si'])),
      p: asChemNum(pick(chem, ['P', 'p'])),
      s: asChemNum(pick(chem, ['S', 's'])),
      b: asChemNum(pick(chem, ['B', 'b', 'boron', 'Boron'])),
      v: asChemNum(pick(chem, ['V', 'v', 'vanadium', 'Vanadium'])),
      nb: asChemNum(pick(chem, ['Nb', 'nb', 'niobium', 'Niobium'])),
      ti: asChemNum(pick(chem, ['Ti', 'ti', 'titanium', 'Titanium'])),
      al: asChemNum(pick(chem, ['Al', 'al', 'AL', 'A1', 'A1*', 'Al*', 'aluminum', 'aluminium'])),
      ca: asChemNum(pick(chem, ['Ca', 'ca', 'calcium'])),
      zr: asChemNum(pick(chem, ['Zr', 'zr', 'zirconium'])),
      zn: asChemNum(pick(chem, ['Zn', 'zn', 'zinc'])),
      sn: asChemNum(pick(chem, ['Sn', 'sn', 'tin'])),
      cu: asChemNum(pick(chem, ['Cu', 'cu'])),
      ni: asChemNum(pick(chem, ['Ni', 'ni'])),
      cr: asChemNum(pick(chem, ['Cr', 'cr'])),
      mo: asChemNum(pick(chem, ['Mo', 'mo'])),
      n: asChemNum(pick(chem, ['N', 'n'])),
      yield_strength: asNum(pick(mech, ['yieldStrength', 'yield_strength'])),
      tensile_strength: asNum(pick(mech, ['tensileStrength', 'tensile_strength'])),
      elongation: asNum(pick(mech, ['elongation'])),
      reduction_area: asNum(pick(mech, ['reductionArea', 'reduction_area'])),
      hardness: asNum(pick(mech, ['hardness'])),
      thickness: asNum(pick(mech, ['thickness', 'thickness_mm', 'plate_thickness']) || pick(phys, ['thickness', 'coatingThickness', 'coating_thickness'])),
      impact_charpy: asNum(pick(mech, ['impactCharpy', 'impact_charpy', 'impactCharpyAverage', 'impact_charpy_average']) || pick(charpy, ['impactCharpy', 'impact_charpy', 'average']) || pick(mech, ['impact_average', 'impactAverage']) || pick(charpy, ['impact_average'])),
      plate_dimension: asStr(pick(mech, ['plateDimension', 'plate_dimension', 'plate dimension', 'Plate dimension', 'Plate_dimension', 'plate_dimensions', 'dimensions', 'dimension']) || pick(phys, ['plateDimension', 'plate_dimension', 'dimensions', 'dimension', 'size'])),
      direction: asStr(pick(mech, ['direction', 'dir', 'Dir', 'testDirection', 'test_direction']) || pick(charpy, ['direction', 'dir']) || pick(rec, ['direction', 'dir'])),
      impact_test_temp: asNum(pick(mech, ['impact_test_temp', 'impactTestTemp', 'temperature', 'testTemperature']) || pick(charpy, ['impact_test_temp', 'impactTestTemp', 'testTemperature', 'temperature']) || pick(rec, ['impact_test_temp', 'impactTestTemp'])),
      impact_coupon_size: asStr(pick(mech, ['impact_coupon_size', 'impactCouponSize', 'testSize', 'size', 'specimenSize']) || pick(charpy, ['impact_coupon_size', 'impactCouponSize', 'testSize', 'size', 'specimenSize']) || pick(phys, ['impact_coupon_size'])),
      impact_specimen_1: asNum(pick(mech, ['impact_specimen_1', 'impactSpecimen1', 'specimen1', 'impact1', 'e1', 'energy1', 'result1']) || pick(charpy, ['impact_specimen_1', 'impactSpecimen1', 'specimen1', 'impact1', 'e1', 'energy1', 'result1'])),
      impact_specimen_2: asNum(pick(mech, ['impact_specimen_2', 'impactSpecimen2', 'specimen2', 'impact2', 'e2', 'energy2', 'result2']) || pick(charpy, ['impact_specimen_2', 'impactSpecimen2', 'specimen2', 'impact2', 'e2', 'energy2', 'result2'])),
      impact_specimen_3: asNum(pick(mech, ['impact_specimen_3', 'impactSpecimen3', 'specimen3', 'impact3', 'e3', 'energy3', 'result3']) || pick(charpy, ['impact_specimen_3', 'impactSpecimen3', 'specimen3', 'impact3', 'e3', 'energy3', 'result3'])),
      impact_average: asNum(pick(mech, ['impact_average', 'impactAverage', 'impactCharpyAverage', 'impact_charpy_average']) || pick(charpy, ['impact_average', 'impactAverage', 'average']) || pick(rec, ['impact_average', 'impactAverage'])),
      country_of_melt: asStr(pick(misc, ['countryOfMeltPour', 'country_of_melt', 'meltCountry', 'countryOfMelt'])),
      country_of_manufacture: asStr(pick(misc, ['countryOfManufacture', 'country_of_manufacture', 'countryOfOrigin', 'origin', 'manufacturedIn', 'madeIn']) || ''),
    };
  };

  const baseRecords = records.length ? records : [];
  if (!baseRecords.length) return [];

  const mappedRecords = baseRecords.map(mapRec);
  const expandedRecords = mappedRecords.flatMap((r) => {
    const heats = splitHeats(r.heat_number);
    return heats.length <= 1 ? [r] : heats.map(h => ({ ...r, heat_number: h }));
  });

  const mergedMap = new Map();
  for (const r of expandedRecords) {
    const heatKey = (r.heat_number || '').toString().trim();
    const batchKey = (r.batch_number || '').toString().trim();
    const key = [heatKey, batchKey || heatKey].join('|');
    if (!heatKey) continue;
    if (!mergedMap.has(key)) mergedMap.set(key, { ...r, batch_number: batchKey || r.batch_number || '' });
  }
  const mergedRecordsFinal = Array.from(mergedMap.values());

  if (baseMtrId) {
    return mergedRecordsFinal.map((r, idx) => ({
      json: {
        ...src,
        file_name: fileName,
        ...r,
        heat_number: (r.heat_number || src.heat_number || '').toString().trim(),
        mtr_id: idx === 0 ? baseMtrId : '',
        force_create: idx > 0,
      },
    }));
  }

  return mergedRecordsFinal
    .filter(r => (r.heat_number || '').toString().trim() !== '')
    .map((r, idx) => ({
      json: {
        ...src,
        file_name: fileName,
        ...r,
        heat_number: (r.heat_number || src.heat_number || '').toString().trim(),
        mtr_id: idx === 0 ? (baseMtrId || '') : '',
        force_create: idx > 0,
      },
    }));
});

return items.map((item, idx) => {
  const j = item.json;
  const source = $items('Normalize For Odoo')[idx]?.json || {};
  const config = $items('Set Odoo + MTR Payload1')[idx]?.json || {};
  const uid = j.result;
  const dbName = (config.db_name || j.db_name || j.database || source.db_name || source.database || 'brannon').toString().trim();
  if (!dbName) throw new Error('Missing database/db_name for Odoo upsert');
  if (!uid) throw new Error(`Odoo authentication failed. uid was: ${uid}`);

  const batch = (source.batch_number || config.batch_number || j.batch_number || '').toString().trim();
  const heat = (source.heat_number || config.heat_number || j.heat_number || '').toString().trim();
  if (!batch && !heat) {
    throw new Error(`Missing batch_number before upsert. Keys: ${Object.keys(source).join(', ')}`);
  }

  const fileName = (source.file_name || config.file_name || j.file_name || source.source_file || config.source_file || j.source_file || '').toString().trim();
    const rawUrl = (config.odoo_url || source.odoo_url || j.odoo_url || '').toString().trim();
  const baseUrl = rawUrl.endsWith('/') ? rawUrl.slice(0, -1) : rawUrl;
  if (!baseUrl) throw new Error('Missing Odoo URL before upsert');

  const payload = {
    mtr_id: source.mtr_id || config.mtr_id || j.mtr_id || '',
    heat_number: heat,
    batch_number: batch || heat,
    piece_no: source.piece_no || config.piece_no || j.piece_no || source.pieceCount || config.pieceCount || j.pieceCount || '',
    force_create: !!(source.force_create || config.force_create || j.force_create),
    grade: source.grade || config.grade || j.grade || '',
    manufacturer: source.manufacturer || config.manufacturer || j.manufacturer || '',
    certificate_number: source.certificate_number || config.certificate_number || j.certificate_number || '',
    certificate_date: source.certificate_date || config.certificate_date || j.certificate_date || '',
    c: source.c || config.c || j.c,
    mn: source.mn || config.mn || j.mn,
    si: source.si || config.si || j.si,
    p: source.p || config.p || j.p,
    s: source.s || config.s || j.s,
    b: source.b || config.b || j.b,
    v: source.v || config.v || j.v,
    nb: source.nb || config.nb || j.nb,
    ti: source.ti || config.ti || j.ti,
    al: source.al || config.al || j.al,
    ca: source.ca || config.ca || j.ca,
    zr: source.zr || config.zr || j.zr,
    zn: source.zn || config.zn || j.zn,
    sn: source.sn || config.sn || j.sn,
    cu: source.cu || config.cu || j.cu,
    ni: source.ni || config.ni || j.ni,
    cr: source.cr || config.cr || j.cr,
    mo: source.mo || config.mo || j.mo,
    n: source.n || config.n || j.n,
    yield_strength: source.yield_strength || config.yield_strength || j.yield_strength,
    tensile_strength: source.tensile_strength || config.tensile_strength || j.tensile_strength,
    elongation: source.elongation || config.elongation || j.elongation,
    reduction_area: source.reduction_area || config.reduction_area || j.reduction_area,
    hardness: source.hardness || config.hardness || j.hardness,
    thickness: source.thickness || config.thickness || j.thickness,
    impact_charpy: source.impact_charpy || config.impact_charpy || j.impact_charpy,
    plate_dimension: source.plate_dimension || config.plate_dimension || j.plate_dimension || '',
    direction: source.direction || config.direction || j.direction || '',
    impact_test_temp: source.impact_test_temp || config.impact_test_temp || j.impact_test_temp,
    impact_coupon_size: source.impact_coupon_size || config.impact_coupon_size || j.impact_coupon_size || '',
    impact_specimen_1: source.impact_specimen_1 || config.impact_specimen_1 || j.impact_specimen_1,
    impact_specimen_2: source.impact_specimen_2 || config.impact_specimen_2 || j.impact_specimen_2,
    impact_specimen_3: source.impact_specimen_3 || config.impact_specimen_3 || j.impact_specimen_3,
    impact_average: source.impact_average || config.impact_average || j.impact_average,
    country_of_melt: source.country_of_melt || config.country_of_melt || j.country_of_melt || '',
    country_of_manufacture: source.country_of_manufacture || config.country_of_manufacture || j.country_of_manufacture || '',
    file_name: fileName,
  };

  return {
    json: {
      rpc_url: `${baseUrl}/jsonrpc`,
      upsert_body: {
        jsonrpc: '2.0',
        method: 'call',
        params: {
          service: 'object',
          method: 'execute_kw',
          args: [
            dbName,
            uid,
            config.odoo_password || source.odoo_password || j.odoo_password,
            'mtr.data',
            'upsert_from_payload',
            [payload],
          ],
        },
        id: 2,
      },
    },
  };
});

return items.map((item, idx) => {
  const j = item.json;
  const dbName = (j.db_name || j.database || '').toString().trim();
  if (!dbName) throw new Error('Missing database/db_name for Odoo auth');
  const rawUrl = (j.odoo_url || '').toString().trim();
  const baseUrl = rawUrl.endsWith('/') ? rawUrl.slice(0, -1) : rawUrl;
  return {
    json: {
      ...j,
      db_name: dbName,
      rpc_url: `${baseUrl}/jsonrpc`,
      auth_body: {
        jsonrpc: '2.0',
        method: 'call',
        params: {
          service: 'common',
          method: 'authenticate',
          args: [dbName, j.odoo_login, j.odoo_password, {}],
        },
        id: 1,
      },
    },
  };
});

return items.map((item) => {
  const root = item.json || {};
  const body = root.body || {};
  const data = root.data || {};

  const fileBase64 =
    root.file_content_base64 ||
    body.file_content_base64 ||
    data.file_content_base64 ||
    root.file_data ||
    body.file_data ||
    data.file_data;

  const mtrId =
    root.mtr_id ||
    body.mtr_id ||
    data.mtr_id ||
    root.mtrId ||
    body.mtrId ||
    data.mtrId;

  const normalizeId = (v) => {
    if (v === undefined || v === null) return '';
    if (typeof v === 'number') return String(v);
    const s = String(v).trim();
    if (!s) return '';
    const m = s.match(/\d+/);
    return m ? m[0] : s;
  };

  const fileName =
    root.file_name ||
    body.file_name ||
    data.file_name ||
    'MTR.pdf';

  if (!fileBase64) {
    throw new Error(`Webhook payload missing file_content_base64. Keys: ${Object.keys(root).join(', ')}`);
  }

  // Simple deterministic hash (no crypto required)
  const hashDjb2 = (str) => {
    let h = 5381;
    for (let i = 0; i < str.length; i++) {
      h = ((h << 5) + h) + str.charCodeAt(i);
      h |= 0;
    }
    return (h >>> 0).toString(16);
  };

  const pdfFingerprint = hashDjb2(fileBase64);

  return {
    json: {
      ...root,
      ...(Object.keys(body).length ? body : {}),
      ...(Object.keys(data).length ? data : {}),
      file_name: fileName,
      file_content_base64: fileBase64,
      pdf_fingerprint: pdfFingerprint,
      mtr_id: normalizeId(mtrId),
    },
    binary: {
      data0: {
        data: fileBase64,
        mimeType: 'application/pdf',
        fileName,
      },
    },
  };
});
